import { Portal } from '@ark-ui/react/portal';
import type { ToastOptions } from '@ark-ui/react/toast';
import {
  Toast as ToastPrimitive,
  Toaster as ToasterPrimitive,
  createToaster,
  useToastContext,
} from '@ark-ui/react/toast';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef } from 'react';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import type { OverlayPortalProps } from '@/lib/moduix/overlayPortal';
import { CloseButton } from '../close-button';
import styles from './Toast.module.css';

const DEFAULT_CLOSE_TRIGGER_LABEL = 'Close toast';

type ToasterProps = Omit<ComponentProps<typeof ToasterPrimitive>, 'children'> &
  OverlayPortalProps & {
    children?: ComponentProps<typeof ToasterPrimitive>['children'];
  };

const Toaster = forwardRef<ComponentRef<typeof ToasterPrimitive>, ToasterProps>(function Toaster(
  { className, portalled = true, portalRef, ...props },
  ref,
) {
  return (
    <Portal disabled={!portalled} container={portalRef}>
      <ToasterPrimitive
        ref={ref}
        data-slot="toast-toaster"
        className={clsx(styles.toaster, normalizeClassName(className))}
        {...props}
      >
        {props.children ?? ((toast) => <DefaultToast toast={toast} />)}
      </ToasterPrimitive>
    </Portal>
  );
});

function DefaultToast({ toast }: { toast: ToastOptions }) {
  return (
    <ToastRoot key={toast.id}>
      {toast.title != null ? <ToastTitle /> : null}
      {toast.description != null ? <ToastDescription /> : null}
      {toast.action ? <ToastActionTrigger>{toast.action.label}</ToastActionTrigger> : null}
      {toast.closable !== false ? <ToastCloseTrigger /> : null}
    </ToastRoot>
  );
}

const ToastRoot = forwardRef<
  ComponentRef<typeof ToastPrimitive.Root>,
  ComponentProps<typeof ToastPrimitive.Root>
>(function ToastRoot({ className, ...props }, ref) {
  return (
    <ToastPrimitive.Root
      ref={ref}
      data-slot="toast-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const ToastTitle = forwardRef<
  ComponentRef<typeof ToastPrimitive.Title>,
  ComponentProps<typeof ToastPrimitive.Title>
>(function ToastTitle({ className, children, ...props }, ref) {
  const toast = useToastContext();

  return (
    <ToastPrimitive.Title
      ref={ref}
      data-slot="toast-title"
      className={clsx(styles.title, normalizeClassName(className))}
      {...props}
    >
      {children === undefined ? toast.title : children}
    </ToastPrimitive.Title>
  );
});

const ToastDescription = forwardRef<
  ComponentRef<typeof ToastPrimitive.Description>,
  ComponentProps<typeof ToastPrimitive.Description>
>(function ToastDescription({ className, children, ...props }, ref) {
  const toast = useToastContext();

  return (
    <ToastPrimitive.Description
      ref={ref}
      data-slot="toast-description"
      className={clsx(styles.description, normalizeClassName(className))}
      {...props}
    >
      {children === undefined ? toast.description : children}
    </ToastPrimitive.Description>
  );
});

const ToastActionTrigger = forwardRef<
  ComponentRef<typeof ToastPrimitive.ActionTrigger>,
  ComponentProps<typeof ToastPrimitive.ActionTrigger>
>(function ToastActionTrigger({ asChild, className, children, ...props }, ref) {
  return (
    <ToastPrimitive.ActionTrigger
      ref={ref}
      asChild={asChild}
      data-slot="toast-action-trigger"
      className={clsx(!asChild && styles.actionTrigger, normalizeClassName(className))}
      {...props}
    >
      {children}
    </ToastPrimitive.ActionTrigger>
  );
});

const ToastCloseTrigger = forwardRef<
  ComponentRef<typeof ToastPrimitive.CloseTrigger>,
  ComponentProps<typeof ToastPrimitive.CloseTrigger>
>(function ToastCloseTrigger(
  { asChild, className, children, 'aria-label': ariaLabel = DEFAULT_CLOSE_TRIGGER_LABEL, ...props },
  ref,
) {
  if (asChild) {
    return (
      <ToastPrimitive.CloseTrigger
        ref={ref}
        asChild
        data-slot="toast-close-trigger"
        aria-label={ariaLabel}
        className={normalizeClassName(className)}
        {...props}
      >
        {children}
      </ToastPrimitive.CloseTrigger>
    );
  }

  return (
    <ToastPrimitive.CloseTrigger asChild>
      <CloseButton.Root
        ref={ref}
        data-slot="toast-close-trigger"
        aria-label={ariaLabel}
        className={clsx(styles.closeTrigger, normalizeClassName(className))}
        {...props}
      >
        {children}
      </CloseButton.Root>
    </ToastPrimitive.CloseTrigger>
  );
});

const Toast = Object.assign(ToastRoot, {
  Root: ToastRoot,
  Title: ToastTitle,
  Description: ToastDescription,
  ActionTrigger: ToastActionTrigger,
  CloseTrigger: ToastCloseTrigger,
  Toaster,
});

export { Toast, Toaster, createToaster };

@layer ui.components {
  .toaster {
    z-index: var(--toast-z-index, var(--z-toast));
  }

  .root {
    --toast-trigger-bg-default: transparent;
    --toast-trigger-bg-hover-default: var(--color-accent);
    --toast-trigger-border-color-default: var(--color-border);
    --toast-trigger-color-default: var(--color-foreground);
    --toast-trigger-focus-ring-color-default: var(--color-ring);
    box-sizing: border-box;
    display: grid;
    width: var(--toast-width, 20rem);
    max-width: calc(100vw - (var(--toast-viewport-inset, 1rem) * 2));
    min-height: var(--toast-min-height, 0);
    align-items: start;
    gap: var(--toast-content-gap, 0.25rem);
    border: var(--toast-border-width, var(--border-width-sm)) solid
      var(--toast-border-color, var(--toast-border-color-default, var(--color-border)));
    border-radius: var(--toast-radius, var(--radius-lg));
    background-color: var(--toast-bg, var(--toast-bg-default, var(--color-popover)));
    color: var(--toast-color, var(--toast-color-default, var(--color-popover-foreground)));
    background-clip: padding-box;
    box-shadow: var(--toast-shadow, var(--shadow-lg));
    padding: var(--toast-padding, 1rem);
    padding-inline-end: calc(var(--toast-padding, 1rem) + var(--toast-close-size, 28px));
    pointer-events: auto;
    user-select: none;
    translate: var(--x) var(--y);
    scale: var(--scale);
    z-index: var(--z-index);
    height: var(--height);
    opacity: var(--opacity);
    will-change: translate, opacity, scale;
    transition:
      translate var(--toast-transition, var(--duration-slow)),
      scale var(--toast-transition, var(--duration-slow)),
      opacity var(--toast-transition, var(--duration-slow)),
      height var(--toast-transition, var(--duration-slow)),
      box-shadow var(--transition-fast);
    transition-timing-function: cubic-bezier(0.21, 1.02, 0.73, 1);

    &[data-state='closed'] {
      transition:
        translate var(--toast-transition-out, var(--duration-slow)),
        scale var(--toast-transition-out, var(--duration-slow)),
        opacity var(--toast-opacity-transition-out, var(--duration-normal));
      transition-timing-function: cubic-bezier(0.06, 0.71, 0.55, 1);
    }

    &[data-type='success'] {
      --toast-bg-default: color-mix(in oklab, var(--color-success) 10%, var(--color-background));
      --toast-border-color-default: color-mix(in oklab, var(--color-success) 34%, transparent);
      --toast-color-default: var(--color-foreground);
      --toast-description-color-default: var(--color-muted-foreground);
    }

    &[data-type='warning'] {
      --toast-bg-default: color-mix(in oklab, var(--color-warning) 13%, var(--color-background));
      --toast-border-color-default: color-mix(in oklab, var(--color-warning) 38%, transparent);
      --toast-color-default: var(--color-foreground);
      --toast-description-color-default: var(--color-muted-foreground);
    }

    &[data-type='destructive'],
    &[data-type='error'] {
      --toast-bg-default: color-mix(in oklab, var(--color-destructive) 9%, var(--color-background));
      --toast-border-color-default: color-mix(in oklab, var(--color-destructive) 35%, transparent);
      --toast-color-default: var(--color-foreground);
      --toast-description-color-default: var(--color-muted-foreground);
    }
  }

  .title {
    display: flex;
    align-items: center;
    gap: var(--toast-title-gap, 0.5rem);
    margin: 0;
    color: inherit;
    font-size: var(--toast-title-font-size, var(--text-sm));
    font-weight: var(--toast-title-font-weight, var(--weight-semibold));
    line-height: var(--toast-title-line-height, var(--line-height-text-sm));
  }

  .description {
    margin: 0;
    color: var(
      --toast-description-color,
      var(--toast-description-color-default, var(--color-muted-foreground))
    );
    font-size: var(--toast-description-font-size, var(--text-sm));
    line-height: var(--toast-description-line-height, var(--line-height-text-sm));
  }

  .actionTrigger {
    display: inline-flex;
    width: max-content;
    align-items: center;
    justify-content: center;
    gap: var(--toast-action-gap, var(--spacing-2));
    min-height: var(--toast-action-min-height, var(--size-xs));
    margin-top: var(--toast-action-margin-top, 0.5rem);
    border: var(--toast-action-border-width, var(--toast-border-width, var(--border-width-sm)))
      solid var(--toast-action-border-color, var(--toast-trigger-border-color-default));
    border-radius: var(--toast-action-radius, var(--radius-sm));
    background: var(--toast-action-bg, var(--toast-trigger-bg-default));
    color: var(--toast-action-color, var(--toast-trigger-color-default));
    padding: var(--toast-action-padding-y, 0.25rem) var(--toast-action-padding-x, 0.5rem);
    font: inherit;
    font-size: var(--toast-action-font-size, var(--text-xs));
    font-weight: var(--toast-action-font-weight, var(--weight-medium));
    line-height: var(--toast-action-line-height, var(--line-height-text-xs));
    cursor: pointer;
    user-select: none;
    white-space: nowrap;
    transition:
      background var(--transition-fast),
      border-color var(--transition-fast),
      color var(--transition-fast);

    &:hover {
      background: var(--toast-action-bg-hover, var(--toast-trigger-bg-hover-default));
    }

    &:focus-visible {
      outline: var(--toast-focus-ring-width, var(--border-width-sm)) solid
        var(--toast-focus-ring-color, var(--toast-trigger-focus-ring-color-default));
      outline-offset: var(--toast-focus-ring-offset, 0);
    }
  }

  .closeTrigger {
    position: absolute;
    inset-block-start: var(--toast-close-offset-top, 0.5rem);
    inset-inline-end: var(--toast-close-offset-right, 0.5rem);
    --close-button-size: var(--toast-close-size, 28px);
    --close-button-icon-size: var(--toast-close-icon-size, 12px);
    --close-button-radius: var(--toast-close-radius, var(--radius-sm));
    --close-button-bg: var(--toast-close-bg, transparent);
    --close-button-bg-hover: var(--toast-close-bg-hover, var(--color-muted));
    --close-button-color: var(--toast-close-color, var(--color-muted-foreground));
    --close-button-color-hover: var(--toast-close-color-hover, var(--color-foreground));
    --close-button-focus-ring-color: var(--toast-focus-ring-color, var(--color-ring));
    --close-button-focus-ring-offset: var(--toast-close-focus-ring-offset, 2px);
    --close-button-focus-ring-width: var(--toast-close-focus-ring-width, var(--border-width-md));
    --close-button-transition: var(--toast-close-transition, var(--transition-default));
  }

  @media (max-width: 40rem) {
    .toaster {
      width: 100%;
    }

    .root {
      inset-inline: 0;
      width: calc(100% - (var(--gap) * 2));
      max-width: none;
    }
  }
}
